const d = $input.first().json;

const meses = ['enero','febrero','marzo','abril','mayo','junio','julio','agosto','septiembre','octubre','noviembre','diciembre'];
const nombreMes = meses[(d.mes - 1)] || `mes ${d.mes}`;

const fmt = (n) => n ? `$${Number(n).toLocaleString('es-CO')}` : '$0';
const fmtPct = (n) => `${Number(n) > 0 ? '+' : ''}${Number(n).toFixed(1)}%`;

const zonas = d.por_zona || [];
const pivotZonaCSV = 'zona,ejecutado,n_ots\n' + zonas.map(z => `${z.zona},${z.ejecutado},${z.n_ots}`).join('\n');

const contratistas = d.top_contratistas || [];
const pivotContratistaCSV = 'contratista_id,contratista_nombre,ejecutado,n_ots\n' + contratistas.map(c => `${c.contratista_id},"${c.contratista_nombre}",${c.total_ejecutado},${c.n_ots}`).join('\n');

const topDesv = d.top_desviaciones || [];
const topDesvTexto = topDesv.slice(0,5).map((t,i) =>
  `${i+1}. ${t.contratista_nombre || 'N/D'} — ${t.zona || ''} — ${t.narrativa_corta || ''}`
).join('\n');

let errorForecastPct = null;
if (d.forecast_dia20 && d.ejecucion_total) {
  errorForecastPct = ((Number(d.forecast_dia20) - Number(d.ejecucion_total)) / Number(d.ejecucion_total)) * 100;
}

return [{
  json: {
    anio: d.anio,
    mes: d.mes,
    nombre_mes: nombreMes,
    ejecucion_total: d.ejecucion_total,
    budget_total: d.budget_total,
    variacion_pct: d.variacion_pct,
    alertas_detectadas: d.alertas_detectadas,
    alertas_cerradas: d.alertas_cerradas,
    alertas_abiertas_cierre: d.abiertas_al_cierre,
    monto_recuperado: d.monto_recuperado,
    error_forecast_pct: errorForecastPct,
    pivot_zona_csv: pivotZonaCSV,
    pivot_contratista_csv: pivotContratistaCSV,
    top_desviaciones_texto: topDesvTexto,
    top_drivers_json: JSON.stringify(topDesv),
    contexto_para_ia: `Mes de cierre: ${nombreMes} ${d.anio}\nEjecución total: ${fmt(d.ejecucion_total)}\nBudget: ${fmt(d.budget_total)}\nVariación: ${fmtPct(d.variacion_pct || 0)}\n\nTop desviaciones:\n${topDesvTexto}\n\nPor zona:\n${zonas.map(z => `${z.zona}: ${fmt(z.ejecutado)} (${z.n_ots} OTs)`).join('\n')}\n\nAlertas detectadas: ${d.alertas_detectadas || 0}\nAlertas cerradas: ${d.alertas_cerradas || 0}\nAlertas abiertas al cierre: ${d.abiertas_al_cierre || 0}\nMonto recuperado por alertas: ${fmt(d.monto_recuperado)}\n${errorForecastPct !== null ? `Error del forecast al día 20: ${fmtPct(errorForecastPct)}` : ''}`
  }
}];

const datos = $('Preparar Datos para IA').first().json;
const iaResponse = $input.first().json;

// Extraer texto de la respuesta de Gemini
const narrativa = iaResponse?.candidates?.[0]?.content?.parts?.[0]?.text || 'Narrativa no disponible';

const meses = ['enero','febrero','marzo','abril','mayo','junio','julio','agosto','septiembre','octubre','noviembre','diciembre'];
const nombreMes = meses[(datos.mes - 1)];
const fmt = (n) => n ? `$${Number(n).toLocaleString('es-CO')}` : '$0';
const fmtPct = (n) => `${Number(n) > 0 ? '+' : ''}${Number(n).toFixed(1)}%`;

const mensajeSlack = `*Cierre OPEX — ${nombreMes.charAt(0).toUpperCase() + nombreMes.slice(1)} ${datos.anio}*

Ejecución total: *${fmt(datos.ejecucion_total)}* | Budget: *${fmt(datos.budget_total)}* | Variación: *${fmtPct(datos.variacion_pct || 0)}*

${narrativa}

Anomalías detectadas: ${datos.alertas_detectadas || 0} | Cerradas: ${datos.alertas_cerradas || 0} | Abiertas al cierre: ${datos.alertas_abiertas_cierre || 0}
Monto recuperado: *${fmt(datos.monto_recuperado)}*
${datos.error_forecast_pct !== null ? `Precisión del forecast (día 20): Error ${fmtPct(datos.error_forecast_pct)}` : ''}`;

return [{
  json: {
    ...datos,
    narrativa_ejecutiva: narrativa,
    mensaje_slack: mensajeSlack
  }
}];
